; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] ! game.protectHeroines && o.ワイルド・ブル.interruption == 0 && game.date % 2 == 0 && random < 0.4
*event_2
;[exp] ! game.protectHeroines && o.ワイルド・ブル.interruption == 0 && game.date % 2 == 1 && random < 0.4

; ワイルド・ブルとの決闘（日によって安全なルートが違う）
@jump storage="duel.ks" target=*wildbull_encounter

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="Be careful of bandits on the mountain pass ahead!"

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("maxLife", 20)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had max HP permanently increased by 20!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

@notice text="Wild Bull's Fort"

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] true

@delevent
@eval exp='o.ワイルド・ブルのアジトを探せ.flag ++'
@wait time=500
@walk turn=w cond='WAY != "w"'
@wait time=100
@walk move=w
@wait time=500
[texton]
[リーダー f=05]「This is...!」[k]
At the end of the mountain pass stood a magnificent fortress. The sign above the entrance read "Wild Bull Fort".[k]
[if exp='! game.isFreeMode']
	[テオ f=06]「Alex...! Their hideout is in a place like this...!」[k]
[endif]
Alex and his gang must be using this place as a base to do all sorts of evil.[k]
[textoff]
@se f=period
@notice text="<y>Found one Wild Bull hideout."

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] true

; イベント時の移動制限。ダンジョンに入れないようにする
[texton]
[テオ f=06]「We should go somewhere else.」[k]
[textoff]
@walk move=e

[eventoff]
;-------------------------------------------------------------------------------
*event_8
;[exp] true

[texton]
[テオ f=06]「The mountain top that [マルエット] was talking about can't be much further ahead...」[k]
[textoff]

[if exp='game.party.curX == 0']
	@walk move=e
[else]
	@walk move=n cond='game.party.curY < 4'
	@walk move=n cond='game.party.curY < 4'
	@walk move=n cond='game.party.curY < 4'
[endif]

[eventoff]
;-------------------------------------------------------------------------------
